import{_ as e,c as o,o as a,a1 as r}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"進階使用：深入設定與最佳化 | opencode-notify教學","description":"學習 opencode-notify 進階設定：設定參考、靜音時段、終端機偵測和最佳實踐。依據個人需求最佳化通知體驗，提升工作效率。","frontmatter":{"title":"進階使用：深入設定與最佳化 | opencode-notify教學","sidebarTitle":"打造你的通知體驗","subtitle":"進階使用：深入設定與最佳化","description":"學習 opencode-notify 進階設定：設定參考、靜音時段、終端機偵測和最佳實踐。依據個人需求最佳化通知體驗，提升工作效率。","tags":["進階","設定","最佳化"],"prerequisite":["start-quick-start","start-how-it-works"],"order":3},"headers":[],"relativePath":"zh-tw/kdcokenny/opencode-notify/advanced/index.md","filePath":"zh-tw/kdcokenny/opencode-notify/advanced/index.md"}'),i={name:"zh-tw/kdcokenny/opencode-notify/advanced/index.md"};function n(l,t,d,c,s,h){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="進階使用-深入設定與最佳化" tabindex="-1">進階使用：深入設定與最佳化 <a class="header-anchor" href="#進階使用-深入設定與最佳化" aria-label="Permalink to &quot;進階使用：深入設定與最佳化&quot;">​</a></h1><p>本章節協助你掌握 opencode-notify 的進階功能，深入了解設定選項、最佳化通知體驗，並依據個人需求打造通知行為。</p><h2 id="學習路徑" tabindex="-1">學習路徑 <a class="header-anchor" href="#學習路徑" aria-label="Permalink to &quot;學習路徑&quot;">​</a></h2><p>建議依以下順序學習本章節內容：</p><h3 id="_1-設定參考" tabindex="-1">1. <a href="./config-reference/">設定參考</a> <a class="header-anchor" href="#_1-設定參考" aria-label="Permalink to &quot;1. [設定參考](./config-reference/)&quot;">​</a></h3><p>全面了解所有可用的設定選項及其作用。</p><ul><li>掌握設定檔的結構和語法</li><li>學習通知音效的客製化方法</li><li>理解子會話通知開關的使用情境</li><li>了解終端機類型覆蓋的設定方法</li></ul><h3 id="_2-靜音時段詳解" tabindex="-1">2. <a href="./quiet-hours/">靜音時段詳解</a> <a class="header-anchor" href="#_2-靜音時段詳解" aria-label="Permalink to &quot;2. [靜音時段詳解](./quiet-hours/)&quot;">​</a></h3><p>學習如何設定靜音時段以避免特定時間被打擾。</p><ul><li>設定靜音時段的開始與結束時間</li><li>處理跨夜的靜音時段（如 22:00 - 08:00）</li><li>在需要時暫時停用靜音功能</li><li>理解靜音時段與其他過濾規則的優先順序</li></ul><h3 id="_3-終端機偵測原理" tabindex="-1">3. <a href="./terminal-detection/">終端機偵測原理</a> <a class="header-anchor" href="#_3-終端機偵測原理" aria-label="Permalink to &quot;3. [終端機偵測原理](./terminal-detection/)&quot;">​</a></h3><p>深入了解終端機自動偵測的工作機制。</p><ul><li>學習外掛如何辨識 37+ 種終端機模擬器</li><li>了解 macOS 平台的焦點偵測實作</li><li>掌握手動指定終端機類型的方法</li><li>理解偵測失敗時的預設行為</li></ul><h3 id="_4-進階用法" tabindex="-1">4. <a href="./advanced-usage/">進階用法</a> <a class="header-anchor" href="#_4-進階用法" aria-label="Permalink to &quot;4. [進階用法](./advanced-usage/)&quot;">​</a></h3><p>掌握設定技巧和最佳實踐。</p><ul><li>避免通知轟炸的設定策略</li><li>依據工作流程調整通知行為</li><li>多視窗和多終端機環境下的設定建議</li><li>效能最佳化和問題排查技巧</li></ul><h2 id="前置條件" tabindex="-1">前置條件 <a class="header-anchor" href="#前置條件" aria-label="Permalink to &quot;前置條件&quot;">​</a></h2><p>開始本章節學習前，建議先完成以下基礎內容：</p><ul><li>✅ <strong>快速開始</strong>：完成外掛安裝和基本設定</li><li>✅ <strong>運作原理</strong>：理解外掛的核心功能和事件監聽機制</li><li>✅ <strong>平台特性</strong>（選用）：了解你所使用平台的特定功能</li></ul><div class="tip custom-block"><p class="custom-block-title">學習建議</p><p>如果你只想客製化通知音效或設定靜音時段，可以直接跳到對應的子頁面。如果遇到問題，可以隨時查閱設定參考章節。</p></div><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>完成本章節學習後，你可以繼續探索：</p><ul><li><strong><a href="./../../faq/troubleshooting/">故障排除</a></strong>：解決常見問題和疑難雜症</li><li><strong><a href="./../../faq/common-questions/">常見問題</a></strong>：了解使用者關心的熱門問題</li><li><strong><a href="./../../appendix/event-types/">事件類型說明</a></strong>：深入學習外掛監聽的所有事件類型</li><li><strong><a href="./../../appendix/config-file-example/">設定檔範例</a></strong>：查看完整的設定範例和註解</li></ul><hr><details><summary><strong>點擊展開查看原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-27</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>設定介面定義</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L30-L48" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>30-48</td></tr><tr><td>預設設定</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L56-L68" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>56-68</td></tr><tr><td>設定載入</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L90-L114" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>90-114</td></tr><tr><td>靜音時段檢查</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L181-L199" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>181-199</td></tr><tr><td>終端機偵測</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L145-L176" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>145-176</td></tr><tr><td>終端機程序名稱映射</td><td><a href="https://github.com/kdcokenny/opencode-notify/blob/main/src/notify.ts#L71-L84" target="_blank" rel="noreferrer"><code>src/notify.ts</code></a></td><td>71-84</td></tr></tbody></table><p><strong>關鍵介面</strong>：</p><ul><li><code>NotifyConfig</code>：設定介面，包含所有可設定項目</li><li><code>quietHours</code>：靜音時段設定（enabled/start/end）</li><li><code>sounds</code>：音效設定（idle/error/permission）</li><li><code>terminal</code>：終端機類型覆蓋（選用）</li></ul><p><strong>關鍵常數</strong>：</p><ul><li><code>DEFAULT_CONFIG</code>：所有設定項目的預設值</li><li><code>TERMINAL_PROCESS_NAMES</code>：終端機名稱到 macOS 程序名稱的映射表</li></ul></details>',25)])])}const u=e(i,[["render",n]]);export{p as __pageData,u as default};
